<script>
const fmt = (n) => {
  if (typeof n !== 'number' || !isFinite(n)) return '$0.00';
  return '$' + n.toFixed(n < 1 ? 4 : 2);
};

async function fetchJson(url, opts) {
  try {
    const r = await fetch(url, opts);
    if (!r.ok) return null;
    return await r.json();
  } catch (e) { return null; }
}

async function refreshHealth() {
  const h = await fetchJson('/health');
  const pill = document.getElementById('health');
  if (h && h.status === 'ok') {
    pill.className = 'health-pill health-ok';
    pill.textContent = '● v' + (h.version || '?');
  } else {
    pill.className = 'health-pill health-down';
    pill.textContent = '● offline';
  }
}

async function refreshCost() {
  const c = await fetchJson('/cost');
  if (!c) return;
  // Per tier
  for (const tier of ['hk', 'so', 'op']) {
    const t = (c.by_tier || {})[tier] || {};
    document.getElementById(`tier-${tier}-count`).textContent = t.count || 0;
    document.getElementById(`tier-${tier}-cost`).textContent = fmt(t.total_usd || 0);
  }
  // Totals
  const tot = c.totals || {};
  document.getElementById('totals-count').textContent = tot.count || 0;
  document.getElementById('totals-cost').textContent = fmt(tot.total_usd || 0);
  document.getElementById('totals-baseline').textContent = fmt(tot.baseline_opus_usd || 0);
  // Savings
  document.getElementById('savings').textContent = fmt(tot.savings_usd || 0);
  const pct = (tot.baseline_opus_usd > 0)
    ? ((tot.savings_usd / tot.baseline_opus_usd) * 100).toFixed(0)
    : 0;
  if ((tot.count || 0) === 0) {
    document.getElementById('savings-context').textContent =
      'Nog geen gecachede calls. Doe één classify-call om te starten.';
  } else {
    document.getElementById('savings-context').textContent =
      `${pct}% goedkoper dan altijd-Opus, over ${tot.count} call${tot.count === 1 ? '' : 's'}.`;
  }
  // Per dag
  const tbody = document.getElementById('by-day-body');
  const days = c.by_day || {};
  const keys = Object.keys(days).sort().reverse();
  if (keys.length === 0) {
    tbody.innerHTML = '<tr><td colspan="4" class="empty">Nog geen calls gecached</td></tr>';
  } else {
    tbody.innerHTML = keys.map(k => {
      const d = days[k];
      return `<tr>
        <td>${k}</td>
        <td class="num">${d.count || 0}</td>
        <td class="num">${fmt(d.total_usd || 0)}</td>
        <td class="num" style="color: var(--color-accent)">${fmt(d.savings_usd || 0)}</td>
      </tr>`;
    }).join('');
  }
}

async function refreshShift() {
  const s = await fetchJson('/shift');
  if (!s) return;
  const v = s.value || 0;
  document.querySelectorAll('.shift-btn').forEach(b => {
    b.classList.toggle('active', parseInt(b.dataset.shift, 10) === v);
  });
}

document.querySelectorAll('.shift-btn').forEach(btn => {
  btn.addEventListener('click', async () => {
    const v = parseInt(btn.dataset.shift, 10);
    await fetchJson('/shift', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ value: v }),
    });
    await refreshShift();
  });
});

// ---- Classify panel handler (sectie 2) ----
const classifyForm = document.getElementById('classify-form');
const classifyBtn = document.getElementById('cf-submit');
const resultBox = document.getElementById('classify-result');
const errorBox = document.getElementById('classify-error');
const resTier = document.getElementById('res-tier');
const resModel = document.getElementById('res-model');
const resRationale = document.getElementById('res-rationale');
const resConfidence = document.getElementById('res-confidence');
const resCache = document.getElementById('res-cache');

classifyForm.addEventListener('submit', async (ev) => {
  ev.preventDefault();
  const scope = document.getElementById('cf-scope').value;
  const locStr = document.getElementById('cf-loc').value;
  const filesStr = document.getElementById('cf-files').value;
  // Lege scope-md weglaten zodat de server 400 (missing required field) teruggeeft
  // i.p.v. een (zinloze) classify op een lege string te draaien.
  const payload = {
    task_id: String(Date.now()),
  };
  if (scope.trim() !== '') payload.scope_md = scope;
  if (locStr !== '') payload.estimated_loc = parseInt(locStr, 10);
  if (filesStr !== '') payload.estimated_files = parseInt(filesStr, 10);

  const originalText = classifyBtn.textContent;
  classifyBtn.disabled = true;
  classifyBtn.textContent = '…';
  resultBox.hidden = true;
  errorBox.hidden = true;

  try {
    const r = await fetch('/classify', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    if (!r.ok) {
      errorBox.textContent = `HTTP ${r.status}: ${r.statusText || 'fout'}`;
      errorBox.hidden = false;
      return;
    }
    const j = await r.json();
    if (!j) {
      errorBox.textContent = 'Lege respons van /classify';
      errorBox.hidden = false;
      return;
    }
    resTier.textContent = '@' + (j.tier || '?');
    resModel.textContent = j.model_hint || '';
    resRationale.textContent = j.rationale || '';
    resConfidence.textContent = (j.confidence != null) ? `${j.confidence}%` : '';
    resCache.hidden = !j.from_cache;
    resultBox.hidden = false;
  } catch (e) {
    errorBox.textContent = `Netwerk-fout: ${e.message || e}`;
    errorBox.hidden = false;
  } finally {
    classifyBtn.disabled = false;
    classifyBtn.textContent = originalText;
  }
});

async function refreshAll() {
  await Promise.all([refreshHealth(), refreshCost(), refreshShift()]);
}

refreshAll();
setInterval(refreshAll, 5000);
</script>
</body>
